func:
if (!msg.scriptPath || msg.scriptPath.indexOf('/path/to/') !== -1) {
    node.warn('Set scriptPath to the full path of garmin-activities-fetch.js in the Setup inject node.');
    return null;
}
flow.set('actScriptPath', msg.scriptPath);
flow.set('actActivitiesPath', msg.activitiesPath || '/kms/10 PMS/Activities');
node.status({ fill: 'green', shape: 'dot', text: 'Config stored' });
return null;

const scriptPath = flow.get('actScriptPath');
if (!scriptPath) { node.warn('Run the Setup inject first.'); return null; }
msg.payload = scriptPath + ' --limit 50';
msg._source = 'poll';
return msg;

const scriptPath = flow.get('actScriptPath');
if (!scriptPath) { node.warn('Run the Setup inject first.'); return null; }
if (!msg.historyYear) { node.warn('Set historyYear on the inject node.'); return null; }
const y = String(msg.historyYear);
msg.payload = scriptPath + ' --start ' + y + '-01-01 --end ' + y + '-12-31';
msg._source = 'historic';
return msg;

const raw = (msg.payload || '').trim();
if (!raw) {
    node.warn('garmin-activities-fetch: no output (check Exec Error debug)');
    return [null, { payload: 'No output from script' }];
}
let activities;
try { activities = JSON.parse(raw); } catch (e) {
    node.warn('JSON parse error: ' + raw.substring(0, 200));
    return [null, { payload: 'JSON parse error: ' + raw.substring(0, 200) }];
}
if (!Array.isArray(activities) || activities.length === 0) {
    return [null, { payload: 'No activities returned' }];
}
node.status({ fill: 'green', shape: 'dot', text: activities.length + ' activities' });
msg.payload = activities;
return [msg, null];

const a = msg.payload;
const activitiesPath = flow.get('actActivitiesPath') || '/kms/10 PMS/Activities';

function slugify(s) {
    return (s || '').toLowerCase()
        .replace(/[^a-z0-9]+/g, '-')
        .replace(/^-+|-+$/g, '')
        .substring(0, 50);
}

const date     = a.date || '';
const parts    = date.split('-');
const yyyy     = parts[0] || 'unknown';
const mm       = parts[1] || 'unknown';
const sport    = ((a.sport_type || a.type || 'activity').toLowerCase().replace(/[^a-z0-9]/g, '-'));
const slug     = slugify(a.name);
const noteFile = date.replace(/-/g, '') + '-' + String(a.activityId) + '-' + sport + '-' + slug + '.md';
msg.activityPath    = activitiesPath + '/' + yyyy + '/' + mm + '/' + noteFile;
msg.activityRelPath = 'Activities/' + yyyy + '/' + mm + '/' + noteFile.replace('.md', '');
msg.activityWikiLink = '[[' + msg.activityRelPath + '|' + (a.name || 'Activity') + ']]';

// Build YAML frontmatter (no quotes on time strings)
const lines = ['---'];
lines.push('garmin_activity_id: ' + a.activityId);
if (a.date)              lines.push('garmin_date: ' + a.date);
if (a.type)              lines.push('garmin_type: ' + a.type);
if (a.sport_type)        lines.push('garmin_sport_type: ' + a.sport_type);
if (a.gear)              lines.push('garmin_gear: ' + a.gear);
lines.push('garmin_name: ' + (a.name || ''));
if (a.dist_km != null)       lines.push('garmin_dist_km: ' + a.dist_km);
if (a.elv_m != null)         lines.push('garmin_elv_m: ' + a.elv_m);
if (a.elapsed_time)          lines.push('garmin_elapsed_time: ' + a.elapsed_time);
if (a.moving_time)           lines.push('garmin_moving_time: ' + a.moving_time);
if (a.start_time)            lines.push('garmin_start_time: ' + a.start_time);
if (a.day_of_week)           lines.push('garmin_day_of_week: ' + a.day_of_week);
if (a.speed_kmh != null)     lines.push('garmin_speed_kmh: ' + a.speed_kmh);
if (a.max_speed_kmh != null) lines.push('garmin_max_speed_kmh: ' + a.max_speed_kmh);
if (a.avg_hr)              lines.push('garmin_avg_hr: ' + a.avg_hr);
if (a.max_hr)              lines.push('garmin_max_hr: ' + a.max_hr);
if (a.calories)            lines.push('garmin_calories: ' + a.calories);
if (a.elv_loss_m != null)  lines.push('garmin_elv_loss_m: ' + a.elv_loss_m);
if (a.aerobic_te != null)  lines.push('garmin_aerobic_te: ' + (+a.aerobic_te).toFixed(1));
if (a.anaerobic_te != null) lines.push('garmin_anaerobic_te: ' + (+a.anaerobic_te).toFixed(1));
if (a.vo2max)              lines.push('garmin_vo2max: ' + a.vo2max);
if (a.avg_power)           lines.push('garmin_avg_power: ' + a.avg_power);
if (a.cadence)             lines.push('garmin_cadence: ' + a.cadence);
lines.push('garmin_refresh: false');
lines.push('---');
lines.push('');

// Display date: "Monday 16 February 2026"
const MONTHS = ['January','February','March','April','May','June','July','August','September','October','November','December'];
let displayDate = a.date || '';
if (a.date && parts.length === 3) {
    const d  = parseInt(parts[2], 10);
    const mo = parseInt(parts[1], 10) - 1;
    displayDate = (a.day_of_week ? a.day_of_week + ' ' : '') + d + ' ' + MONTHS[mo] + ' ' + yyyy;
}
const startHHMM = (a.start_time || '').substring(0, 5);
const gearSuffix = a.gear ? ' · ' + a.gear : '';
const subtitle = '**' + (a.type || 'Activity') + '**'
    + (displayDate ? ' · ' + displayDate : '')
    + (startHHMM   ? ' · ' + startHHMM   : '')
    + gearSuffix;

// Comma-format large integers (e.g. 1319 → "1,319")
function fmtInt(n) {
    return String(Math.round(n)).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
}

// Avg moving speed: dist_km / moving hours
function calcMvgSpeed(dist_km, moving_time) {
    if (!dist_km || !moving_time) return null;
    const p = moving_time.split(':').map(Number);
    if (p.length !== 3) return null;
    const hrs = p[0] + p[1] / 60 + p[2] / 3600;
    if (hrs === 0) return null;
    return +(dist_km / hrs).toFixed(1);
}
const avg_mvg_speed = calcMvgSpeed(a.dist_km, a.moving_time);

lines.push('# ' + (a.name || 'Activity'));
lines.push('');
lines.push(subtitle);
lines.push('');

// Table 1: Distance | Start Time | Moving Time | Elapsed Time
lines.push('| Distance | Start Time | Moving Time | Elapsed Time |');
lines.push('| :------: | :--------: | :---------: | :----------: |');
lines.push('| ' + (a.dist_km != null ? a.dist_km + ' km' : '—')
    + ' | ' + (startHHMM || '—')
    + ' | ' + (a.moving_time  || '—')
    + ' | ' + (a.elapsed_time || '—') + ' |');
lines.push('');

// Table 2: Avg Speed | Avg Mvg Speed | Max Speed | Elev Gain
lines.push('| Avg Speed | Avg Mvg Speed | Max Speed | Elev Gain |');
lines.push('| --------- | ------------- | --------- | --------- |');
lines.push('| ' + (a.speed_kmh     != null ? a.speed_kmh + ' kph'     : '—')
    + ' | ' + (avg_mvg_speed != null ? avg_mvg_speed + ' kph' : '—')
    + ' | ' + (a.max_speed_kmh != null ? a.max_speed_kmh + ' kph' : '—')
    + ' | ' + (a.elv_m != null ? fmtInt(a.elv_m) + ' m' : '—') + ' |');
lines.push('');

// Table 3: Avg HR | Max HR (only if present)
if (a.avg_hr || a.max_hr) {
    lines.push('| Avg HR | Max HR |');
    lines.push('| :-----: | :-----: |');
    lines.push('| ' + (a.avg_hr ? a.avg_hr + ' bpm' : '—')
        + ' | ' + (a.max_hr ? a.max_hr + ' bpm' : '—') + ' |');
    lines.push('');
}

// Training Effect (only if any value >= 1)
function teLabel(v) {
    if (v < 1) return 'No Benefit';
    if (v < 2) return 'Minor';
    if (v < 3) return 'Maintaining';
    if (v < 4) return 'Improving';
    if (v < 5) return 'Highly Improving';
    return 'Overreaching';
}
const showAerobic = a.aerobic_te  != null && a.aerobic_te  >= 1;
const showAnaero  = a.anaerobic_te != null && a.anaerobic_te >= 1;
if (showAerobic || showAnaero) {
    const teParts = [];
    if (showAerobic) teParts.push('Aerobic '   + (+a.aerobic_te).toFixed(1)   + ' (' + teLabel(a.aerobic_te)   + ')');
    if (showAnaero)  teParts.push('Anaerobic ' + (+a.anaerobic_te).toFixed(1) + ' (' + teLabel(a.anaerobic_te) + ')');
    lines.push('**Training Effect** · ' + teParts.join(' · '));
    lines.push('');
}

// Cadence, power, VO2
const extraParts = [];
if (a.cadence)   extraParts.push('**Cadence** ' + a.cadence + ' rpm');
if (a.avg_power) extraParts.push('**Power** ' + a.avg_power + ' W');
if (a.vo2max)    extraParts.push('**VO\u2082 Max** ' + a.vo2max);
if (extraParts.length > 0) {
    lines.push(extraParts.join(' · '));
    lines.push('');
}

lines.push('[View on Garmin Connect](https://connect.garmin.com/activity/' + a.activityId + ')');
lines.push('');

msg.activityNote = lines.join('\n');
msg.activityId   = a.activityId;
msg.activityDate = a.date;
msg.activityName = a.name || 'Activity';
msg.filename     = msg.activityPath;
return msg;

// Check flow context — have we written this activity before?
const ids = flow.get('actWrittenIds') || {};
const id  = String(msg.activityId);
if (!ids[id]) {
    // New activity — write it immediately, no file read needed
    msg.payload  = msg.activityNote;
    msg.filename = msg.activityPath;
    return [msg, null];  // output 1: write
}
// Already written — read the file to check garmin_refresh flag
return [null, msg];  // output 2: check refresh

// File exists and was read — check for garmin_refresh: true
const content  = (typeof msg.payload === 'string') ? msg.payload : '';
const fmMatch  = content.match(/^---\n([\s\S]*?)\n---/);
const fm       = fmMatch ? fmMatch[1] : '';
if (!/^garmin_refresh:\s*true\s*$/m.test(fm)) {
    return null;  // flag not set — skip
}
node.warn('Refreshing activity ' + msg.activityId + ' (' + msg.activityName + ')');
msg.payload  = msg.activityNote;
msg.filename = msg.activityPath;
return msg;

const ids = flow.get('actWrittenIds') || {};
ids[String(msg.activityId)] = true;
flow.set('actWrittenIds', ids);
return msg;
